import logging
import logging.handlers
import os

# Define log directory and file name
LOG_DIR = '/var/log/application'
LOG_FILE_NAME = 'application.log'
LOG_FILE_PATH = os.path.join(LOG_DIR, LOG_FILE_NAME)

# Ensure the log directory exists
os.makedirs(LOG_DIR, exist_ok=True)

# Create a logger
logger = logging.getLogger('application_logger')
logger.setLevel(logging.INFO) # Set the minimum level for this logger

# Define a formatter for log messages
# %(asctime)s - Timestamp of the log record
# %(name)s - Name of the logger
# %(levelname)s - Text logging level for the message (e.g., INFO, DEBUG, ERROR)
# %(process)d - Process ID
# %(thread)d - Thread ID
# %(filename)s:%(lineno)d - File name and line number where the log call was made
# %(message)s - The log message itself
formatter = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - P%(process)d T%(thread)d - %(filename)s:%(lineno)d - %(message)s'
)

# Create a RotatingFileHandler for log rotation
# maxBytes: Log file will be rotated after reaching this size (e.g., 10 MB)
# backupCount: Number of backup files to keep (e.g., application.log.1, application.log.2, etc.)
# encoding: Specify encoding for the log file
file_handler = logging.handlers.RotatingFileHandler(
    LOG_FILE_PATH,
    maxBytes=10 * 1024 * 1024,  # 10 MB
    backupCount=5,              # Keep 5 backup logs
    encoding='utf-8'
)
file_handler.setFormatter(formatter)
file_handler.setLevel(logging.INFO) # Set the minimum level for this handler

# Optionally, add a StreamHandler to also output logs to console (useful for development/testing)
# For production, this might be removed or set to a higher level
# stream_handler = logging.StreamHandler()
# stream_handler.setFormatter(formatter)
# stream_handler.setLevel(logging.DEBUG) # Example: show all debug logs on console

# Add handlers to the logger
logger.addHandler(file_handler)
# logger.addHandler(stream_handler)

